select , b.res_type, b.res_page,d.user_name as deal_obj_name ,u.user_name as create_by_name,t.reci_obj_name from men_task a left join men_res_com b on a.res_com_id = b.res_com_id left join po_users d on d.user_id = a.deal_obj_id and a.deal_type ='HUMAN' left join po_users u on u.user_id = a.create_by LEFT JOIN ( SELECT c.task_id, STRING_AGG( CASE WHEN c.reci_type IN ('HUMAN', 'HUMAN_ASSISTANT', 'ASSITENT') THEN u.user_name ELSE r.resource_name END, ', ' ) AS reci_obj_name FROM men_task_rec_obj c LEFT JOIN po_users u ON c.reci_obj_id = u.user_id AND c.reci_type IN ('HUMAN' , 'HUMAN_ASSISTANT', 'ASSITENT') LEFT JOIN ss_resource r ON c.reci_obj_id = r.resource_id AND c.reci_type IN ('DIG_EMPLOYEE', 'AGENT') GROUP BY c.task_id ) t ON a.task_id = t.task_id
and a.task_type = #{qo.taskType}
and a.title like concat('%', #{qo.title}, '%')
and a.status_cd = #{qo.statusCd}
and a.deal_obj_id = #{qo.dealObjId}
and a.send_obj_id = #{qo.sendObjId}
and a.status_cd in
#{item}
and a.p_task_id = #{qo.pTaskId}
and a.session_id = #{qo.sessionId}
order by a.create_time desc

